SELECT COUNT(*)
FROM auction_inquiry
WHERE auction_id = #{auctionId}

SELECT id, inquiryType, answerStatus, createdAt, title, content, answer, answeredAt, auctionId FROM ( SELECT ai.id AS id, 'PURCHASE' AS inquiryType, ai.auction_id AS auctionId, ai.status AS answerStatus, ai.created_at AS createdAt, ai.title AS title, ai.content AS content, ai.answer AS answer, ai.answered_at AS answeredAt FROM auction_inquiry ai WHERE ai.writer_id = #{memberId}
UNION ALL
SELECT ai.id AS id, 'SALES' AS inquiryType, ai.auction_id AS auctionId, ai.status AS answerStatus, ai.created_at AS createdAt, ai.title AS title, ai.content AS content, ai.answer AS answer, ai.answered_at AS answeredAt FROM auction_inquiry ai INNER JOIN auction a ON ai.auction_id = a.id WHERE a.seller_id = #{memberId} ) t
t.inquiryType = #{type}
ORDER BY createdAt
ASC
DESC
LIMIT #{pageRequest.size} OFFSET #{pageRequest.offset}

SELECT COUNT(*)
FROM (
SELECT 'PURCHASE' AS inquiryType
FROM auction_inquiry ai
WHERE ai.writer_id = #{memberId}

UNION ALL

SELECT 'SALES' AS inquiryType
FROM auction_inquiry ai
INNER JOIN auction a
ON ai.auction_id = a.id
WHERE a.seller_id = #{memberId}
) t


        t.inquiryType = #{type}
